export function getSocialPlatform(type: string): SocialPlatform | undefined {
  return SOCIAL_PLATFORMS.find((p) => p.type === type);
}

export function SocialIcon({
  type,
  className,
}: {
  type: string;
  className?: string;
}) {
  const platform = getSocialPlatform(type);
  if (!platform) return null;
  const Icon = platform.icon;
  return <Icon className={className} />;
}
